var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"이건 건물이잖아?","JPN":"これは、建物？","ENG":"Hmm? This is a building.","TWN":"這裡竟然有一座建築？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"이면세계 한복판에 국제 공항보다 큰 시설이 있을 줄이야.","JPN":"裏世界のど真ん中に、国際空港よりデカい建造物があったとはな。","ENG":"Never expected to see a facility bigger than an airport in the middle of the Counterside.","TWN":"沒想到在異界深處竟然還藏著一座比機場還要大的設施。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"하지만 이미 완전히 무너졌군. 일대에 큰 폭발이 있었나본데.","JPN":"でもすでに崩壊してる。この辺りで大きな爆発があったみたいだ。","ENG":"But it's a complete wreck. There must have been a large explosion.","TWN":"但已經徹底坍塌了。看來這片區域曾發生過大爆炸。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"힉스는 저 잔해 아래에 있어.","JPN":"ヒックスはあの残骸の下にいる。","ENG":"Hicks is under that wreckage.","TWN":"希克斯就在那片廢墟下面。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"좌표를 보니, 아무래도 건물의 지하는 아직 무너지지 않은 것 같네.","JPN":"座標を見る限り、この建物の地下はまだ崩れずに残っているようだ。","ENG":"The coordinates tell me that basement hasn't collapsed yet.","TWN":"從座標上看，大樓的地下室還沒有塌陷。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"지하로 통하는 대피용 통로군. 꽤 넓은데.","JPN":"地下に通ずる避難通路か。結構広いな。","ENG":"It's an emergency exit leading to the basement. It's quite large.","TWN":"這是通往地下的逃生通道。相當寬敞啊。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"다들 멈춰.","JPN":"みんな止れ。","ENG":"Hold.","TWN":"大家停下來。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"전방에 동면성 침식체야.","JPN":"前方に冬眠性侵食体だ。","ENG":"Dormant C.O. up ahead.","TWN":"前方有冬眠的侵蝕體。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"길에 빼곡히 들어섰군. 전부 잠들어 있는 건가?","JPN":"すげえ数だ、道が塞がっちまってる。すべて眠ってるのか？","ENG":"They're all packed in here. Are they all asleep?","TWN":"密密麻麻的擠在通道上。它們都睡著了嗎？"},"stage":{"bg":"UNDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"침식체가 잠을 잔다고? 생긴 거랑 안 어울리게 고상한 생활을 누리고 계셨구만.","JPN":"侵食体が睡眠だと？　あんな見た目の割りにずいぶん温和な生活をおくってんだな。","ENG":"C.O.s sleep? Guess they have it good down here unlike their ugly mugs.","TWN":"侵蝕體睡著了？想不到侵蝕體也這麼好命。"},"stage":{"bg":"UNDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"챔버의 대균열에서만 출몰하는 침식 개체의 공통된 특징이지.","JPN":"チェンバーの大亀裂で見られる侵食体特有の性質だ。","ENG":"It's a common trait among C.O.s that appear in Chamber's Grand Dimension Crevice.","TWN":"這是僅存在於強巴大峽谷的侵蝕體的共同特徵。"},"stage":{"bg":"UNDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"실수로 건들지만 않으면 놈들도 깨지 않을 거야.","JPN":"触れたりしなければ、奴らが目覚めることはない。","ENG":"Just don't touch them, and they won't wake up.","TWN":"只要你不驚擾到它們，就不會醒來。"},"stage":{"bg":"UNDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"잠깐, 대장.","JPN":"ちょっと待ってくれ、隊長。","ENG":"Wait, Captain.","TWN":"等一下，隊長。"},"stage":{"bg":"UNDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"왜 우리가 이 녀석들 사이로 지나가야 하는 것처럼 말하는 건데?","JPN":"まさか俺たちはあいつらの間を通り抜けなきゃならないってことなのか？","ENG":"Why are you saying that as if we're going to walk past them?","TWN":"你為什麼說得好像我們要從這些傢伙中間過去一樣？"},"stage":{"bg":"UNDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"먼저 갈 테니 조심해서 따라와.","JPN":"私が先に行くからついて来なさい。","ENG":"I’ll lead. Follow carefully.","TWN":"我先過去，你們小心一點，跟緊我。"},"stage":{"bg":"UNDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"진심이야?","JPN":"マジかよ？","ENG":"Are you serious?","TWN":"喂……你是認真的？"},"stage":{"bg":"UNDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"이런 것들과 싸우는 것보단 골백번 낫지.","JPN":"まぁ、こんな化け物と戦闘になるよりかはマシか。","ENG":"Beats fighting them.","TWN":"總比和這些東西戰鬥要好一百倍。"},"stage":{"bg":"UNDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM1","text":{"KOREA":"가보죠.","JPN":"行きましょう。","ENG":"Guess we're doing this.","TWN":"我們走吧。"},"stage":{"bg":"UNDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM1","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"…미치겠군.","JPN":"……勘弁してくれよ。","ENG":"...Yeesh.","TWN":"……都是瘋子。"},"stage":{"bg":"UNDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"같이 가…!","JPN":"ちょっ、俺を置いてくな……！","ENG":"Hey, wait up...!","TWN":"欸欸，等等我……！"},"stage":{"bg":"UNDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"젠장… 우리 얼마나 걸었지? 이 통로는 대체 어디까지 이어지는 거야…?","JPN":"くっ……結構歩いたと思うが、いったいこの通路はどこまで続いてるんだ？","ENG":"Dammit... How long have we been walking for? Where does this even lead to...?","TWN":"該死……我們走了多久了？這個通道到底通向哪裡……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L34_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"쉿.","JPN":"しっ。","ENG":"Shush.","TWN":"噓。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"차단문을 찾았어.","JPN":"遮蔽扉がある。","ENG":"I found the gate.","TWN":"我找到了阻斷門。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"전력이 없으니 강제로 열어야 해.","JPN":"電力はないから強制的にこじ開けるしかない。","ENG":"We'll have to force it open since there's no power.","TWN":"沒有電源，我們需要強行打開它。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"내가 해보지.","JPN":"俺がやってみるぜ。","ENG":"I'll do it.","TWN":"我試試看。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"이야. 팔 힘 좋은데, 형씨?","JPN":"おおっ。すごい力だな、兄ちゃん。","ENG":"Yo bro, that's some good arm strength, eh?","TWN":"哇喔，兄弟，你的臂力不錯啊？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"그런데, 방금 소란 때문에 놈들이 깨는 건 아니겠…","JPN":"でも、今の物音で奴らが起きてこなければいいが……","ENG":"Hope the noise didn't wake–","TWN":"但是，剛剛的動靜會不會吵醒了它們……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"내가…","JPN":"それにしても……","ENG":"What...","TWN":"噢噢……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"지금 뭘 보고 있는 거지?","JPN":"これはいったい何なんだ？","ENG":"am I looking at?","TWN":"看看我們發現了什麼？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"이 전산장치들은 다 뭐야? 먼지만 남은 이면세계치곤 너무 멀쩡하잖아?","JPN":"全部、電算装置か？　塵と化した裏世界にこんなしっかりしたものがあったのか？","ENG":"What's with all these computing devices? It's in pretty good shape considering this is the Counterside.","TWN":"這些電腦設備……對於異界來說，這裡是不是太乾淨了點？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"대정화전쟁 이후, 한때 챔버의 많은 기업들이 앞다퉈 이면세계를 개척하려 했었지.","JPN":"大浄化戦争後、一時チェンバーの多くの企業勢が裏世界の開拓に乗り出した。","ENG":"After the Great Purification War, many of Chamber's corporations were eager to explore the Counterside.","TWN":"淨化之戰結束後，強巴的眾多特遣勢力都在競相探索異界。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이것도 그 시절에 지어졌던 전초기지 중 하나일 가능성이 높아.","JPN":"ここも、その当時に建てられた前哨基地の一つである可能性が高い。","ENG":"This is likely one of the frontier bases built during that time.","TWN":"這很可能是那個時期建造的前哨站之一。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"버려진 하수처리장을 개조했군.","JPN":"放置された下水処理場を改造したようだな。","ENG":"Looks like they converted it from an abandoned sewage treatment plant.","TWN":"他們對廢棄的汙水處理廠進行了改造。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"내부에 이런 시설이 숨어있단 걸 눈치채지 못한 것도 당연해.","JPN":"内部にこんな施設が隠れていたなんて、気づかないのも納得できる。","ENG":"It's understandable that they didn't notice such a place.","TWN":"難怪我沒有注意到裡面隱藏著這樣的設施。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"지알로, 저기 있는 단말기를 복원할 수 있겠어?","JPN":"ジャッロ、あそこの端末機を復旧できそうか？","ENG":"Giallo, can you restore the terminal over there?","TWN":"賈洛，你能恢復那邊的終端嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM1","text":{"KOREA":"시설 관리용 터미널 같은데… 폭발에 휘말린 것치곤 손상이 그리 심하지 않네요.","JPN":"施設管理用のターミナルのようですが……爆発に巻き込まれた割りには、大した損傷はなさそうです。","ENG":"It looks like a facility management terminal. Considering the explosion... the damage doesn't seem too bad.","TWN":"看起來像是個設施管理用的終端……雖然被捲入了爆炸，但損傷並不嚴重。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM1","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM1","text":{"KOREA":"30분만 주시면 해결해보죠.","JPN":"これなら30分で直せます。","ENG":"Give me 30 minutes.","TWN":"給我30分鐘解決。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM1","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"좋아. 그럼 우린 그동안 힉스를 찾으러 이동한다.","JPN":"よし。それならその間、私たちはヒックスの捜索に向かう。","ENG":"All right. We'll find Hicks in the meantime.","TWN":"好的。那這段時間裡，我們去找希克斯。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};